<?php require __DIR__.'/includes/pawn_bootstrap.php';$id=(int)($_GET['id']??0);$st=$conn->prepare("SELECT pe.*,c.customer_name FROM pawn_entries pe JOIN customers c ON c.id=pe.customer_id WHERE pe.id=? AND pe.business_id=? AND pe.branch_id=? AND pe.status IN ('Active','Partially Paid')");$st->bind_param('iii',$id,$businessId,$branchId);$st->execute();$pawn=$st->get_result()->fetch_assoc();$st->close();if(!$pawn)die('Active pawn not found.');$st=$conn->prepare('SELECT MAX(to_date) last_date FROM pawn_interest_collections WHERE pawn_entry_id=? AND business_id=?');$st->bind_param('ii',$id,$businessId);$st->execute();$last=$st->get_result()->fetch_assoc()['last_date']??null;$st->close();$from=$last?:$pawn['pawn_date'];$st=$conn->prepare('SELECT id,method_name FROM payment_methods WHERE business_id=? AND is_active=1');$st->bind_param('i',$businessId);$st->execute();$methods=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$theme=pawn_theme($conn,$businessId);?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Interest Collection</title><?php include 'includes/links.php';include __DIR__.'/includes/pawn_styles.php';?></head><body><?php include 'includes/sidebar.php';?><main class="app-main"><?php include 'includes/nav.php';?><div class="content-wrap"><form class="pawn-card" id="form"><div class="pawn-head"><div><div class="pawn-title">Interest Collection</div><div class="small text-muted"><?=pawn_e($pawn['pawn_no'].' · '.$pawn['customer_name'])?></div></div><a href="pawn-view.php?id=<?=$id?>" class="btn btn-light btn-sm">Back</a></div><input type="hidden" name="csrf_token" value="<?=pawn_e($pawnCsrf)?>"><input type="hidden" name="pawn_entry_id" value="<?=$id?>"><div class="section"><div class="row g-3"><div class="col-md-3"><label class="field-label">Collection date</label><input type="date" class="form-control" name="collection_date" value="<?=date('Y-m-d')?>"></div><div class="col-md-3"><label class="field-label">From</label><input type="date" class="form-control" name="from_date" value="<?=pawn_e($from)?>"></div><div class="col-md-3"><label class="field-label">To</label><input type="date" class="form-control" name="to_date" value="<?=date('Y-m-d')?>"></div><div class="col-md-3"><label class="field-label">Interest amount</label><input type="number" step="0.01" class="form-control calc" name="interest_amount" required></div><div class="col-md-3"><label class="field-label">Penalty</label><input type="number" step="0.01" class="form-control calc" name="penalty_amount" value="0"></div><div class="col-md-3"><label class="field-label">Total</label><input type="number" step="0.01" class="form-control" name="total_amount" readonly></div><div class="col-md-3"><label class="field-label">Payment method</label><select class="form-select" name="payment_method_id"><option value="">Select</option><?php foreach($methods as $m):?><option value="<?=$m['id']?>"><?=pawn_e($m['method_name'])?></option><?php endforeach?></select></div><div class="col-md-3"><label class="field-label">Suggested</label><button type="button" class="btn btn-light w-100" id="calc">Calculate</button></div></div></div><div class="section text-end"><button class="btn btn-theme">Save Interest</button></div></form></div></main><?php include 'includes/script.php';?><script src="assets/js/script.js"></script><script>const f=document.getElementById('form'),p=<?=json_encode((float)$pawn['balance_principal'])?>,r=<?=json_encode((float)$pawn['interest_percent'])?>,period=<?=json_encode($pawn['interest_period'])?>;function total(){f.total_amount.value=((parseFloat(f.interest_amount.value)||0)+(parseFloat(f.penalty_amount.value)||0)).toFixed(2)}document.querySelectorAll('.calc').forEach(x=>x.oninput=total);document.getElementById('calc').onclick=()=>{const a=new Date(f.from_date.value),b=new Date(f.to_date.value);let d=Math.max(1,Math.round((b-a)/86400000)+1),v=period==='Daily'?p*r/100*d:period==='Yearly'?p*r/100*d/365:p*r/100*d/30;f.interest_amount.value=v.toFixed(2);total()};f.onsubmit=async e=>{e.preventDefault();const x=await fetch('api/pawn-interest-save.php',{method:'POST',body:new FormData(f)}),j=await x.json();alert(j.message);if(j.success)location.href='pawn-view.php?id=<?=$id?>'};</script></body></html>
